"let strategyOpen=false,labMarket=null,labBacktest=null,labAnalysis=null;function fmtPct(n){return n==null?'—':`${Number(n).toFixed(3)}%`}\nfunction deriveLabRows(rows,params){const out=rows.map(r=>({...r}));for(let i=0;i<out.length;i++){const start=Math.max(0,i-11),win=out.slice(start,i+1),prices=win.map(r=>r.price),vols=win.map(r=>r.volume||0),mid=prices.reduce((a,b)=>a+b,0)/prices.length,prev=out[i-1]?.price??out[i].price,prev2=out[i-2]?.price??prev,ret1=prev?((out[i].price-prev)/prev)*100:0,prevRet=prev2?((prev-prev2)/prev2)*100:0;out[i].midpoint=mid;out[i].distance=Math.abs(mid?((out[i].price-mid)/mid)*100:0);out[i].pullback=mid?((mid-Math.min(...prices))/mid)*100:0;out[i].reversal=(prevRet<0&&ret1>0)?Math.abs(prevRet)+Math.abs(ret1):0;out[i].volRatio=vols.reduce((a,b)=>a+b,0)?((out[i].volume||0)/(vols.reduce((a,b)=>a+b,0)/vols.length)):1;out[i].volatility=mid?((Math.max(...prices)-Math.min(...prices))/mid)*100:0;out[i].accel=ret1-prevRet;}return out;}\nfunction drawLab(){if(!labMarket||!labBacktest)return;const params={distance_min:Number($('LAB_DISTANCE_MIN').value),pullback_min:Number($('LAB_PULLBACK_MIN').value),reversal_min:Number($('LAB_REVERSAL_MIN').value),volume_ratio_min:Number($('LAB_VOL_RATIO_MIN').value),volatility_min:Number($('LAB_VOLATILITY_MIN').value),accel_min:Number($('LAB_ACCEL_MIN').value),target_pct:Number($('LAB_TARGET_PCT').value),stop_pct:Number($('LAB_STOP_PCT').value),trail_trigger_pct:Number($('LAB_TRAIL_TRIGGER_PCT').value),retrace_pct:Number($('LAB_RETRACE_PCT').value),max_hold_bars:Number($('LAB_MAX_HOLD_BARS').value),friction_pct:Number($('LAB_FRICTION_PCT').value)};const rows=deriveLabRows(labMarket.rows||[],params);const hits=rows.filter(r=>r.price<=r.midpoint&&r.distance>=params.distance_min&&r.pullback>=params.pullback_min&&r.reversal>=params.reversal_min&&r.volRatio>=params.volume_ratio_min&&r.volatility>=params.volatility_min&&r.accel>=params.accel_min);$('labMsg').textContent=`${hits.length} candidate reversals under current visible thresholds`;const c=$('labChart'),x=c.getContext('2d'),W=c.width,H=c.height,padL=72,padR=20,padT=18,padB=40;x.clearRect(0,0,W,H);x.fillStyle='#09111a';x.fillRect(0,0,W,H);if(rows.length<2)return;const vals=[...rows.map(r=>r.price),...rows.map(r=>r.midpoint)];const min=Math.min(...vals),max=Math.max(...vals),rng=max-min||1,px=i=>padL+i/(rows.length-1)*(W-padL-padR),py=v=>H-padB-((v-min)/rng)*(H-padT-padB);x.strokeStyle='rgba(255,255,255,.06)';for(let i=0;i<6;i++){let y=padT+i*(H-padT-padB)/5;x.beginPath();x.moveTo(padL,y);x.lineTo(W-padR,y);x.stroke();x.fillStyle='#91a5bc';x.font='12px sans-serif';x.fillText((max-(i/5)*rng).toFixed(2),8,y+4)}x.strokeStyle='#f4c542';x.setLineDash([5,4]);x.beginPath();rows.forEach((r,i)=>{i?x.lineTo(px(i),py(r.midpoint)):x.moveTo(px(i),py(r.midpoint));});x.stroke();x.setLineDash([]);x.strokeStyle='#7ec8ff';x.lineWidth=2;x.beginPath();rows.forEach((r,i)=>{i?x.lineTo(px(i),py(r.price)):x.moveTo(px(i),py(r.price));});x.stroke();hits.forEach(r=>{const i=rows.indexOf(r);x.fillStyle='#20d29a';x.beginPath();x.arc(px(i),py(r.price),3.5,0,Math.PI*2);x.fill();});$('labSamples').textContent=String(rows.length);$('labTurns').textContent=String(labAnalysis?.turn_count??'—');$('labBestNet').textContent=fmtPct(labBacktest?.best?.avg_net_pct);$('labBestWin').textContent=labBacktest?.best?.win_rate==null?'—':`${(labBacktest.best.win_rate*100).toFixed(1)}%`;const tops=(labBacktest.top_results||[]).slice(0,3);$('labTopSets').innerHTML=tops.map((r,i)=>`<div class=\"stat\"><div class=\"label\">Set ${i+1}</div><div class=\"value\">${fmtPct(r.avg_net_pct)}</div><div class=\"muted\">Win ${(r.win_rate*100).toFixed(1)}% · rev ${fmtPct(r.params.reversal_min)}</div></div>`).join('');}\nasync function loadLab(){const [mr,br,ar]=await Promise.all([fetch('/api/strategy-lab/market-data'),fetch('/api/strategy-lab/backtest'),fetch('/api/strategy-lab/analysis')]);labMarket=await mr.json();labBacktest=await br.json();labAnalysis=await ar.json();const p=labBacktest.best?.params||{};[['LAB_DISTANCE_MIN','distance_min'],['LAB_PULLBACK_MIN','pullback_min'],['LAB_REVERSAL_MIN','reversal_min'],['LAB_VOL_RATIO_MIN','volume_ratio_min'],['LAB_VOLATILITY_MIN','volatility_min'],['LAB_ACCEL_MIN','accel_min'],['LAB_TARGET_PCT','target_pct'],['LAB_STOP_PCT','stop_pct'],['LAB_TRAIL_TRIGGER_PCT','trail_trigger_pct'],['LAB_RETRACE_PCT','retrace_pct'],['LAB_MAX_HOLD_BARS','max_hold_bars'],['LAB_FRICTION_PCT','friction_pct']].forEach(([id,key])=>{if($(id)) $(id).value=p[key]??''});drawLab();}\nasync function load(){const [sr,hr]=await Promise.all([fetch('/api/hq/status'),fetch('/api/bloc/history')]);const sres=await sr.json();const hres=await hr.json();history=(hres.points||[]).slice(-480);render(sres.live.scalp_pool||{});}async function loadParams(){"
